from math import *
import time
import matplotlib.pyplot as plt
from decimal import Decimal, getcontext
def Euler(): # DISCLAIMER : This program calculates the solution to n decimal places. 
    getcontext().prec = 400
    pi = Decimal(3.)
    e = Decimal(2.)
    X = []
    Y = []
    best = 1000
    bestN = 0
    for n in range(-999, 1000):
        if n == 0:
            continue
        
        rootN = Decimal(abs(n))**Decimal(0.5)
        if sqrt(abs(n))%1==0:
            continue
        if n > 0:
            toAnalyse = cos(pi*rootN)
        else:
            toAnalyse = e**Decimal(pi*rootN)
        X.append(n)
        Y.append(min(toAnalyse.real%1, 1-toAnalyse.real%1))
        if min(toAnalyse.real%1, 1-toAnalyse.real%1)<=best:
            
            best = min(toAnalyse.real%1, 1-toAnalyse.real%1)
            bestN = n
            print(best, bestN)
    plt.plot(X, Y, 'o')
    plt.show()
    return bestN

start = time.time()
print(Euler())
print(f'Took {time.time()-start}s')
